import java.io.*;

public class Main {
    private static boolean isInterleave(String s1, String s2, String s3) {
        int m = s1.length();
        int n = s2.length();
        if (m + n != s3.length()) return false;
        boolean[][] dp = new boolean[m + 1][n + 1];
        dp[0][0] = true;
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                if (i == 0 && j == 0) continue;
                int k = i + j - 1;
                if (i > 0 && s1.charAt(i - 1) == s3.charAt(k) && dp[i - 1][j]) {
                    dp[i][j] = true;
                }
                if (j > 0 && s2.charAt(j - 1) == s3.charAt(k) && dp[i][j - 1]) {
                    dp[i][j] = true;
                }
            }
        }
        return dp[m][n];
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String s1 = br.readLine();
            if (s1 == null) s1 = "";
            String s2 = br.readLine();
            if (s2 == null) s2 = "";
            String s3 = br.readLine();
            if (s3 == null) s3 = "";
            sb.append(isInterleave(s1, s2, s3) ? "True" : "False");
            if (t != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

